+@preconcurrency import ApplicationServices
+import AppKit
+import CoreGraphics
+import Foundation
+
+struct FrontmostApplicationContext: Equatable, Sendable {
+    let processID: pid_t
+    let bundleIdentifier: String?
+}
+
+struct FrontmostWindowContext: Equatable, Sendable {
+    let windowID: Int
+    let frame: CGRect
+}
+
+enum PasteTargetObservationStatus: Equatable, Sendable {
+    case editable
+    case nonEditable
+}
+
+struct PasteTargetObservation: Equatable, Sendable {
+    let processID: pid_t
+    let windowID: Int?
+    let status: PasteTargetObservationStatus
+}
+
+protocol FrontmostApplicationProviding {
+    func frontmostApplication() -> FrontmostApplicationContext?
+}
+
+protocol FrontmostWindowResolving {
+    func frontmostWindow(for processID: pid_t) -> FrontmostWindowContext?
+}
+
+protocol AccessibilityElement: AnyObject {
+    var role: String? { get }
+    var isEnabled: Bool? { get }
+    var isEditable: Bool? { get }
+    var isFocused: Bool { get }
+    var hasSelectedTextRange: Bool { get }
+    var isValueSettable: Bool { get }
+    var children: [any AccessibilityElement] { get }
+    var parent: (any AccessibilityElement)? { get }
+    var frame: CGRect? { get }
+    var windowID: Int? { get }
+    func stringValue() -> String?
+    func markerText() -> String?
+}
+
+protocol AccessibilityApplicationReading: AnyObject {
+    func focusedUIElement() -> (any AccessibilityElement)?
+    func focusedWindowElement() -> (any AccessibilityElement)?
+}
+
+protocol AccessibilityApplicationCreating {
+    func application(processID: pid_t) -> any AccessibilityApplicationReading
+}
+
+protocol PasteTargetMonitoring: AnyObject {
+    var currentObservation: PasteTargetObservation? { get set }
+    func start()
+    func synchronize(to application: FrontmostApplicationContext?)
+    func record(_ observation: PasteTargetObservation)
+    func clearObservation()
+}
+
+struct WorkspaceFrontmostApplicationProvider: FrontmostApplicationProviding {
+    func frontmostApplication() -> FrontmostApplicationContext? {
+        guard let application = NSWorkspace.shared.frontmostApplication else {
+            return nil
+        }
+
+        return FrontmostApplicationContext(
+            processID: application.processIdentifier,
+            bundleIdentifier: application.bundleIdentifier
+        )
+    }
+}
+
+struct CoreGraphicsFrontmostWindowResolver: FrontmostWindowResolving {
+    func frontmostWindow(for processID: pid_t) -> FrontmostWindowContext? {
+        guard
+            let windowList = CGWindowListCopyWindowInfo([.optionOnScreenOnly, .excludeDesktopElements], kCGNullWindowID) as? [[String: Any]]
+        else {
+            return nil
+        }
+
+        for entry in windowList {
+            guard
+                entry[kCGWindowOwnerPID as String] as? pid_t == processID,
+                entry[kCGWindowLayer as String] as? Int == 0,
+                (entry[kCGWindowAlpha as String] as? Double ?? 0) > 0,
+                let boundsObject = entry[kCGWindowBounds as String] as? NSDictionary,
+                let frame = CGRect(dictionaryRepresentation: boundsObject),
+                let windowID = entry[kCGWindowNumber as String] as? Int
+            else {
+                continue
+            }
+
+            return FrontmostWindowContext(windowID: windowID, frame: frame)
+        }
+
+        return nil
+    }
+}
+
+struct AXAccessibilityApplicationFactory: AccessibilityApplicationCreating {
+    func application(processID: pid_t) -> any AccessibilityApplicationReading {
+        AXAccessibilityApplication(processID: processID)
+    }
+}
+
+final class AXAccessibilityApplication: AccessibilityApplicationReading {
+    private let applicationElement: AXUIElement
+
+    init(processID: pid_t) {
+        applicationElement = AXUIElementCreateApplication(processID)
+    }
+
+    func focusedUIElement() -> (any AccessibilityElement)? {
+        guard let element = copyElement(attribute: kAXFocusedUIElementAttribute as CFString) else {
+            return nil
+        }
+
+        return AXAccessibilityElement(element: element)
+    }
+
+    func focusedWindowElement() -> (any AccessibilityElement)? {
+        guard let element = copyElement(attribute: kAXFocusedWindowAttribute as CFString) else {
+            return nil
+        }
+
+        return AXAccessibilityElement(element: element)
+    }
+
+    private func copyElement(attribute: CFString) -> AXUIElement? {
+        var value: CFTypeRef?
+        let error = AXUIElementCopyAttributeValue(applicationElement, attribute, &value)
+        guard error == .success, let element = value, CFGetTypeID(element) == AXUIElementGetTypeID() else {
+            return nil
+        }
+
+        return unsafeDowncast(element, to: AXUIElement.self)
+    }
+}
+
+final class AXAccessibilityElement: AccessibilityElement {
+    private let element: AXUIElement
+
+    init(element: AXUIElement) {
+        self.element = element
+    }
+
+    var role: String? {
+        attributeValue(kAXRoleAttribute as CFString)
+    }
+
+    var isEnabled: Bool? {
+        attributeValue(kAXEnabledAttribute as CFString)
+    }
+
+    var isEditable: Bool? {
+        attributeValue("AXEditable" as CFString)
+    }
+
+    var isFocused: Bool {
+        attributeValue(kAXFocusedAttribute as CFString) ?? false
+    }
+
+    var hasSelectedTextRange: Bool {
+        attribute(kAXSelectedTextRangeAttribute as CFString) != nil
+    }
+
+    var isValueSettable: Bool {
+        var settable = DarwinBoolean(false)
+        let error = AXUIElementIsAttributeSettable(element, kAXValueAttribute as CFString, &settable)
+        return error == .success && settable.boolValue
+    }
+
+    var children: [any AccessibilityElement] {
+        guard let rawChildren = attribute(kAXChildrenAttribute as CFString) as? [AXUIElement] else {
+            return []
+        }
+
+        return rawChildren.map(AXAccessibilityElement.init)
+    }
+
+    var parent: (any AccessibilityElement)? {
+        guard let parent = copyElement(attribute: kAXParentAttribute as CFString) else {
+            return nil
+        }
+
+        return AXAccessibilityElement(element: parent)
+    }
+
+    var frame: CGRect? {
+        guard
+            let positionObject = attribute(kAXPositionAttribute as CFString),
+            CFGetTypeID(positionObject) == AXValueGetTypeID(),
+            let sizeObject = attribute(kAXSizeAttribute as CFString),
+            CFGetTypeID(sizeObject) == AXValueGetTypeID()
+        else {
+            return nil
+        }
+
+        let positionValue = unsafeDowncast(positionObject, to: AXValue.self)
+        let sizeValue = unsafeDowncast(sizeObject, to: AXValue.self)
+        var position = CGPoint.zero
+        var size = CGSize.zero
+        guard
+            AXValueGetType(positionValue) == .cgPoint,
+            AXValueGetValue(positionValue, .cgPoint, &position),
+            AXValueGetType(sizeValue) == .cgSize,
+            AXValueGetValue(sizeValue, .cgSize, &size)
+        else {
+            return nil
+        }
+
+        return CGRect(origin: position, size: size)
+    }
+
+    var windowID: Int? {
+        nil
+    }
+
+    func stringValue() -> String? {
+        if let string: String = attributeValue(kAXValueAttribute as CFString) {
+            return string
+        }
+
+        if let attributed = attribute(kAXValueAttribute as CFString) as? NSAttributedString {
+            return attributed.string
+        }
+
+        return nil
+    }
+
+    func markerText() -> String? {
+        guard
+            let startMarker = attribute("AXStartTextMarker" as CFString),
+            let endMarker = attribute("AXEndTextMarker" as CFString)
+        else {
+            return nil
+        }
+
+        var range: CFTypeRef?
+        let markers = [startMarker, endMarker] as CFArray
+        guard
+            AXUIElementCopyParameterizedAttributeValue(
+                element,
+                "AXTextMarkerRangeForUnorderedTextMarkers" as CFString,
+                markers,
+                &range
+            ) == .success,
+            let range,
+            let text = parameterizedValue("AXStringForTextMarkerRange" as CFString, parameter: range) as? String
+        else {
+            return nil
+        }
+
+        return text
+    }
+
+    private func copyElement(attribute name: CFString) -> AXUIElement? {
+        guard let value = attribute(name), CFGetTypeID(value) == AXUIElementGetTypeID() else {
+            return nil
+        }
+
+        return unsafeDowncast(value, to: AXUIElement.self)
+    }
+
+    private func attribute(_ name: CFString) -> CFTypeRef? {
+        var value: CFTypeRef?
+        let error = AXUIElementCopyAttributeValue(element, name, &value)
+        guard error == .success else {
+            return nil
+        }
+
+        return value
+    }
+
+    private func parameterizedValue(_ name: CFString, parameter: CFTypeRef) -> CFTypeRef? {
+        var value: CFTypeRef?
+        let error = AXUIElementCopyParameterizedAttributeValue(element, name, parameter, &value)
+        guard error == .success else {
+            return nil
+        }
+
+        return value
+    }
+
+    private func attributeValue<T>(_ name: CFString) -> T? {
+        attribute(name) as? T
+    }
+}
+
+final class AccessibilityPasteTargetEvaluator {
+    private static let textEntryRoles = Set([
+        kAXTextFieldRole as String,
+        kAXTextAreaRole as String,
+        kAXComboBoxRole as String,
+    ])
+
+    func isTextEntryRole(_ role: String?) -> Bool {
+        guard let role else {
+            return false
+        }
+
+        return Self.textEntryRoles.contains(role)
+    }
+
+    func findPasteTarget(
+        startingAt element: any AccessibilityElement,
+        focusContext: Bool,
+        remainingDepth: Int = 12
+    ) -> (any AccessibilityElement)? {
+        let hasFocusContext = focusContext || element.isFocused
+        if qualifies(element, focusContext: hasFocusContext) {
+            return element
+        }
+
+        guard remainingDepth > 0 else {
+            return nil
+        }
+
+        let orderedChildren = element.children.sorted { lhs, rhs in
+            if lhs.isFocused == rhs.isFocused {
+                return false
+            }
+
+            return lhs.isFocused && !rhs.isFocused
+        }
+
+        for child in orderedChildren {
+            if let target = findPasteTarget(startingAt: child, focusContext: hasFocusContext, remainingDepth: remainingDepth - 1) {
+                return target
+            }
+        }
+
+        return nil
+    }
+
+    private func qualifies(_ element: any AccessibilityElement, focusContext: Bool) -> Bool {
+        if element.isEnabled == false {
+            return false
+        }
+
+        if focusContext {
+            if element.isEditable == true || element.isValueSettable {
+                return true
+            }
+
+            return isTextEntryRole(element.role)
+        }
+
+        return element.hasSelectedTextRange && element.isValueSettable
+    }
+}
+
+final class FocusedElementTextExtractor {
+    func extractText(from element: any AccessibilityElement) -> String? {
+        var current: (any AccessibilityElement)? = element
+        var remainingAncestors = 8
+
+        while let element = current {
+            if let text = normalize(element.stringValue()) ?? normalize(element.markerText()) {
+                return text
+            }
+
+            guard remainingAncestors > 0 else {
+                break
+            }
+
+            remainingAncestors -= 1
+            current = element.parent
+        }
+
+        return nil
+    }
+
+    private func normalize(_ text: String?) -> String? {
+        guard let trimmed = text?.trimmingCharacters(in: .whitespacesAndNewlines), !trimmed.isEmpty else {
+            return nil
+        }
+
+        return trimmed
+    }
+}
+
+private struct FocusedElementResolution {
+    let directElement: (any AccessibilityElement)?
+    let fallbackElement: (any AccessibilityElement)?
+}
+
+private final class FocusedElementResolver {
+    func resolve(in application: any AccessibilityApplicationReading) -> FocusedElementResolution {
+        let directElement = application.focusedUIElement()
+        guard directElement == nil else {
+            return FocusedElementResolution(directElement: directElement, fallbackElement: nil)
+        }
+
+        return FocusedElementResolution(
+            directElement: nil,
+            fallbackElement: findFocusedDescendant(in: application.focusedWindowElement(), remainingDepth: 12)
+        )
+    }
+
+    private func findFocusedDescendant(
+        in element: (any AccessibilityElement)?,
+        remainingDepth: Int
+    ) -> (any AccessibilityElement)? {
+        guard let element else {
+            return nil
+        }
+
+        if element.isFocused {
+            return element
+        }
+
+        guard remainingDepth > 0 else {
+            return nil
+        }
+
+        let orderedChildren = element.children.sorted { lhs, rhs in
+            if lhs.isFocused == rhs.isFocused {
+                return false
+            }
+
+            return lhs.isFocused && !rhs.isFocused
+        }
+
+        for child in orderedChildren {
+            if let focused = findFocusedDescendant(in: child, remainingDepth: remainingDepth - 1) {
+                return focused
+            }
+        }
+
+        return nil
+    }
+}
+
+final class AccessibilityPasteTargetDetector: PasteTargetDetecting {
+    private let accessibilityChecker: any AccessibilityPermissionChecking
+    private let applicationProvider: any FrontmostApplicationProviding
+    private let windowResolver: any FrontmostWindowResolving
+    private let applicationFactory: any AccessibilityApplicationCreating
+    private let monitor: any PasteTargetMonitoring
+    private let evaluator = AccessibilityPasteTargetEvaluator()
+    private let focusedElementResolver = FocusedElementResolver()
+
+    init(
+        accessibilityChecker: any AccessibilityPermissionChecking = AccessibilityPermissionChecker(),
+        applicationProvider: any FrontmostApplicationProviding = WorkspaceFrontmostApplicationProvider(),
+        windowResolver: any FrontmostWindowResolving = CoreGraphicsFrontmostWindowResolver(),
+        applicationFactory: any AccessibilityApplicationCreating = AXAccessibilityApplicationFactory(),
+        monitor: any PasteTargetMonitoring
+    ) {
+        self.accessibilityChecker = accessibilityChecker
+        self.applicationProvider = applicationProvider
+        self.windowResolver = windowResolver
+        self.applicationFactory = applicationFactory
+        self.monitor = monitor
+    }
+
+    func canPasteToFocusedElement() -> Bool {
+        guard accessibilityChecker.isTrusted(prompt: false) else {
+            return false
+        }
+
+        guard let applicationContext = applicationProvider.frontmostApplication() else {
+            return false
+        }
+
+        monitor.start()
+        monitor.synchronize(to: applicationContext)
+
+        guard let windowContext = windowResolver.frontmostWindow(for: applicationContext.processID) else {
+            return false
+        }
+
+        let application = applicationFactory.application(processID: applicationContext.processID)
+        let resolution = focusedElementResolver.resolve(in: application)
+
+        if let directElement = resolution.directElement {
+            guard let target = evaluator.findPasteTarget(startingAt: directElement, focusContext: true) else {
+                return false
+            }
+
+            recordObservation(for: target, processID: applicationContext.processID, fallbackWindowID: windowContext.windowID)
+            return true
+        }
+
+        if let fallbackElement = resolution.fallbackElement,
+           let target = evaluator.findPasteTarget(startingAt: fallbackElement, focusContext: true) {
+            recordObservation(for: target, processID: applicationContext.processID, fallbackWindowID: windowContext.windowID)
+            return true
+        }
+
+        guard
+            let observation = monitor.currentObservation,
+            observation.processID == applicationContext.processID,
+            observation.windowID == windowContext.windowID,
+            observation.status == .editable
+        else {
+            return false
+        }
+
+        return true
+    }
+
+    private func recordObservation(for element: any AccessibilityElement, processID: pid_t, fallbackWindowID: Int) {
+        monitor.record(
+            PasteTargetObservation(
+                processID: processID,
+                windowID: element.windowID ?? fallbackWindowID,
+                status: .editable
+            )
+        )
+    }
+}
